  "arguments": {
    "path": "checkers_game/checkers.py",
    "content": "import numpy as np

class Checkers:
    def __init__(self):
        self.board = None
        self.current_player = 'white'
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        self.board = np.zeros((8, 8), dtype=int)
        for row in range(3, 5):
            for col in range(0, 8, 2):
                self.board[row, col] = -1  # White pieces
                self.board[7-row, 7-col] = 1  # Black pieces

    def print_board(self):
        # Print the current board state
        for row in range(8):
            for col in range(8):
                if self.board[row, col] == -1:
                    print('W', end=' ')  # White piece
                elif self.board[row, col] == 1:
                    print('B', end=' ')  # Black piece
                else:
                    print('.', end=' ')  # Empty square
            print()

    def is_valid_move(self, from_row, from_col, to_row, to_col):
        # Check if the move is valid
        if abs(from_row - to_row) != 1 or abs(from_col - to_col) != 1:
            return False
        piece = self.board[from_row, from_col]
        if piece == 0:
            return False
        elif (piece == -1 and from_row <= to_row) or (piece == 1 and from_row >= to_row):
            return False
        return True

    def make_move(self, from_row, from_col, to_row, to_col):
        # Make a move on the board
        if self.is_valid_move(from_row, from_col, to_row, to_col):
            piece = self.board[from_row, from_col]
            self.board[from_row, from_col] = 0
            self.board[to_row, to_col] = piece
            # Handle captures
            if abs(to_row - from_row) == 2:
                capture_row = (to_row + from_row) // 2
                capture_col = (to_col + from_col) // 2
                self.board[capture_row, capture_col] = 0
        else:
            print('Invalid move')

    def switch_player(self):
        # Switch to the other player
        if self.current_player == 'white':
            self.current_player = 'black'
        else:
            self.current_player = 'white'

    def run(self):
        # Run the game loop
        while True:
            print(f'Player {self.current_player}'s turn')
            self.print_board()
            from_row, from_col = map(int, input('Enter move (from_row from_col to_row to_col): ').split())
            self.make_move(from_row, from_col, to_row, to_col)
            self.switch_player()

if __name__ == '__main__':
    game = Checkers()
    game.run()"
  }
}
